import { Link } from "react-router-dom";
import classes from "./Tab.module.css";

const MainHeaderTab = (props) => {
  const setTabHandler = () => {
    props.tabState.setSelectedTab(props.title);
  };

  console.log("TABS RERENDERED");

  let isSelected = false;
  if (props.tabState.selectedTab === props.title) {
    isSelected = true;
  }

  return (
    <div
      className={`${classes["tab"]} ${isSelected && classes["selected"]}`}
      onClick={setTabHandler}
    >
      <Link to={props.link} style={{ textDecoration: "none" }}>
        {props.title}
      </Link>
    </div>
  );
};

export default MainHeaderTab;
